import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileHandler {

    private static final String BASE_DIRECTORY = "C:\\data\\";

    public static void readUserFile(String fileName) {
        try {
            Path filePath = Paths.get(BASE_DIRECTORY, fileName).normalize().toAbsolutePath();
            if (!filePath.startsWith(Paths.get(BASE_DIRECTORY))) {
                System.out.println("Access to files outside base directory is not allowed.");
                return;
            }

            byte[] content = Files.readAllBytes(filePath);
            System.out.println(new String(content));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input containing path traversal
        readUserFile(userInput);
    }
}

### Explanation:
취약유형: Path Traversal
